def _extract_import_from(
    node: ast.ImportFrom,
) -> list[dict[str, Any]]:
    imports: list[dict[str, Any]] = []

    module_name = node.module or ""

    if node.level:
        module_name = ("." * node.level) + module_name

    for imported_name in node.names:
        imports.append(
            {
                "type": "from_import",
                "module": module_name,
                "name": imported_name.name,
