def _is_private_method(
    method_name: Any,
) -> bool:
    if not isinstance(method_name, str):
        return False

    if method_name in {
        "__init__",
        "__call__",
        "__enter__",
        "__exit__",
    }:
        return False

    return method_name.startswith("_")

